import"./ticker-BxUDbM2L.js";import{i as a}from"./country-page-CK6BdUjw.js";import"./utils-Owvk3OYq.js";import"./breadcrumbs-CxxVGuAV.js";a({countryCode:"KW",currency:"KWD",flag:"🇰🇼",nameEn:"Kuwait",nameAr:"الكويت",fixedPeg:!1,decimals:3,timezone:"Asia/Kuwait",relatedCountries:[{file:"uae.html",nameEn:"UAE",nameAr:"الإمارات",flag:"🇦🇪"},{file:"saudi-arabia.html",nameEn:"Saudi Arabia",nameAr:"السعودية",flag:"🇸🇦"},{file:"qatar.html",nameEn:"Qatar",nameAr:"قطر",flag:"🇶🇦"},{file:"bahrain.html",nameEn:"Bahrain",nameAr:"البحرين",flag:"🇧🇭"},{file:"oman.html",nameEn:"Oman",nameAr:"عُمان",flag:"🇴🇲"},{file:"egypt.html",nameEn:"Egypt",nameAr:"مصر",flag:"🇪🇬"}],faqEn:[{q:"What is today's gold price in Kuwait?",a:"The Kuwaiti Dinar (KWD) is one of the world's most valuable currencies, trading at approximately 0.31 KWD per USD. Because of this, gold gram prices in KWD appear numerically small but represent high real value. Prices are updated every 90 seconds from the live XAU/USD spot rate."},{q:"Why is the Kuwaiti Dinar so valuable?",a:"The KWD is pegged to a basket of currencies rather than solely to the US Dollar, making it less volatile than most Gulf currencies. Kuwait's substantial oil wealth and the Central Bank's conservative monetary policy have consistently maintained its high purchasing power."},{q:"What karats are popular in Kuwait?",a:"21K and 22K gold are the most popular choices for jewellery in Kuwait. 24K (pure gold) is primarily sought for investment purposes such as bars and coins."},{q:"Is there VAT on gold in Kuwait?",a:"As of 2025, Kuwait has not implemented a Value Added Tax (VAT), making it one of the most tax-efficient places to buy gold in the GCC region. Buyers pay only the spot price plus any jeweller's making charges."}],faqAr:[{q:"ما هو سعر الذهب اليوم في الكويت؟",a:"يُعدّ الدينار الكويتي (KWD) من أعلى العملات قيمةً في العالم، إذ يبلغ سعر صرفه نحو 0.31 دينار مقابل الدولار الأمريكي. لذلك تبدو أسعار الذهب بالغرام منخفضةً من الناحية الرقمية، غير أنها تعكس قيمةً حقيقيةً مرتفعة. يتم تحديث الأسعار كل 90 ثانية استناداً إلى سعر XAU/USD الفوري."},{q:"لماذا يتمتع الدينار الكويتي بهذه القيمة المرتفعة؟",a:"يرتبط الدينار الكويتي بسلة من العملات وليس بالدولار الأمريكي وحده، مما يجعله أقل تذبذباً من معظم عملات الخليج. وقد أسهمت الثروة النفطية الكبيرة لدى الكويت وسياسة بنكها المركزي المحافظة في الحفاظ على قوته الشرائية العالية باستمرار."},{q:"ما هي العيارات الأكثر شيوعاً في الكويت؟",a:"يُعدّ عيار 21 وعيار 22 الأكثر شيوعاً للمجوهرات في الكويت، أما عيار 24 (الذهب الخالص) فيُستخدم أساساً للأغراض الاستثمارية كالسبائك والعملات الذهبية."},{q:"هل يُطبَّق ضريبة القيمة المضافة على الذهب في الكويت؟",a:"حتى عام 2025، لم تُطبّق الكويت ضريبة القيمة المضافة (VAT)، مما يجعلها من أكثر دول مجلس التعاون الخليجي كفاءةً من الناحية الضريبية عند شراء الذهب. يدفع المشترون سعر الذهب الفوري فقط مضافاً إليه أجور الصياغة لدى الصائغ."}]});
